#!/usr/bin/env python3
"""
setup_client_vm.py
Run this ON dc-client AND dc-server2 to create all necessary project files.
Usage:  python3 setup_client_vm.py
"""
import os, base64

files = {}
files['client/chat_app.py'] = ''
files['client/server_client.py'] = ''
files['middleware/dme.py'] = ''
files['config.json'] = ''

BASE = os.path.expanduser("~/distributed-chatroom")
for rel, b64 in files.items():
    path = os.path.join(BASE, rel)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print("  created:", path)
for d in ["logs", "client", "middleware"]:
    os.makedirs(os.path.join(BASE, d), exist_ok=True)
open(os.path.join(BASE, "client/__init__.py"), "a").close()
open(os.path.join(BASE, "middleware/__init__.py"), "a").close()
print()
print("Client VM setup complete! Files are in ~/distributed-chatroom/")
